  "marin-san-anselmo-ds2": { description: "Women’s Dual-Sport Step-Thru · 700C. Marin’s top-spec dual-sport with a step-thru frame and Women’s Fit Geometry (narrower bars, women’s saddle, short-reach levers). Loaded with modern components — SR/Suntour NEX fork with hydraulic lockout, Shimano 2x8 gearing, and hydraulic disc brakes. Equally at home in traffic or on local doubletrack.", specs: {"Frame": "Series 2 Dual Sport, 6061 Aluminum, 700C, Women’s Fit Geometry, Step-Through Design, Fender & Rack Mounts", "Fork": "SR/Suntour NEX Disc HLO, 63mm Travel, Hydraulic Lockout, Preload Adjust", "Rear Derailleur": "Shimano Acera RD-M3000", "Front Derailleur": "Shimano Acera FD-M3000", "Shifters": "Shimano Altus SL-M315 Rapidfire, 2×8", "Crankset": "Alloy Compact, 46/30T", "Cassette": "SunRace 11-34T, 8-speed", "Chain": "KMC X8", "Bottom Bracket": "68mm, Threaded", "Brakes": "Tektro Hydraulic Disc", "Rotors": "160mm front & rear", "Tires": "Vee Tile / Kenda Kahn 700C × 40mm", "Rims": "Marin Alloy Double Wall, 32H", "Handlebar": "Marin Alloy, Narrowed Women’s Width", "Stem": "Marin Alloy, Adjustable-Reach Levers", "Grips": "Marin Comfort Ergonomic", "Seatpost": "Alloy, 27.2mm", "Saddle": "Marin Women’s Adventure", "Mounts": "Kickstand, Fender, Front & Rear Rack", "Fit Notes": "Women’s geometry: narrower bars, shorter reach levers, women’s saddle"}, images: ["https://cdn.shopify.com/s/files/1/0931/9455/1645/files/2021_San_Anselmo_DS1_Color.jpg?v=1744825386", "https://cdn.shopify.com/s/files/1/0931/9455/1645/files/2021_San_Anselmo_DS1_GalleryE_1.jpg?v=1744825385", "https://cdn.shopify.com/s/files/1/0931/9455/1645/files/2021_San_Anselmo_DS1_GalleryE_2.jpg?v=1744825385"], colorImages: { "Grey/Orange": ["https://marinbikes.com/cdn/shop/files/2025_MARIN_BIKES_SAN_ANSELMO_DS2_GRAY_SIDE.png?v=1753869100&width=1000"] } },
  "marin-bolinas-ridge-1-27-5": { description: "Entry-Level Recreational Hardtail · 27.5\". Your entry point to Marin mountain biking. Series 1 6061 aluminum frame, 100mm fork travel, real MTB tires. Shimano Tourney 3x7 drivetrain with Power CX7 mechanical discs — rugged, fixable, ready for trails and fire roads. Size-appropriate 27.5\" (S/M) or 29\" (M/L/XL) wheels.", specs: {"Frame": "Series 1, 6061 Aluminum, 27.5\" (S/M) or 29\" (M/L/XL), Low Standover, 68mm BB, 135mm QR Dropouts", "Fork": "SR Suntour XCE Disc, 100mm Travel, Preload Adjust, 46mm Offset", "Rear Derailleur": "Shimano Tourney RD-TY300", "Front Derailleur": "Shimano Tourney FD-TY710", "Shifters": "Shimano Tourney EF41, 3×7 Rapidfire", "Crankset": "FC-TY301, 42/34/24T Triple", "Cassette": "SunRace 11-34T, 7-speed", "Chain": "KMC Z7", "Bottom Bracket": "68mm, Threaded", "Brakes": "Power CX7 Mechanical Disc", "Rotors": "160mm front & rear", "Tires": "MTB 27.5\" or 29\" × 2.25\"", "Rims": "Marin Alloy Double Wall, 32H", "Handlebar": "Marin Alloy MTB Riser", "Stem": "Marin Alloy, 31.8mm", "Grips": "Marin MTB Lock-On", "Seatpost": "Alloy, 30.9mm", "Saddle": "Marin MTB Sport", "Headset": "Semi-Integrated, Tapered"}, images: ["https://still-term-f1ec.taocaruso77.workers.dev/api/img?url=https://marinbikes.com/cdn/shop/files/2025_MARIN_BIKES_BOLINAS_RIDGE_1_27_CHARCOAL_SIDE.png?v=1755782077&width=1000","https://still-term-f1ec.taocaruso77.workers.dev/api/img?url=https://marinbikes.com/cdn/shop/files/Marin_Bolinas_1_Orange.png?v=1771260317&width=1000","https://still-term-f1ec.taocaruso77.workers.dev/api/img?url=https://marinbikes.com/cdn/shop/files/MarinBolinasLifestyle_23_-2.jpg?v=1771260317&width=1000"], colorImages: { "Green": ["https://marinbikes.com/cdn/shop/files/Marin_Bolinas_1_Green27.png?v=1771260317"] } },
